var log = dist_default("book-cli:books");
async function getBooksByAuthor(author) {
  log("Fetching books for %s", author);
  const res = await fetch(`https://openlibrary.org/search.json?author=${encodeURIComponent(author)}`);
  const data = await res.json();
  const books = data.docs.map((b) => ({
    title: b.title,
    key: b.key,
    year: b.first_publish_year
  }));
  log("Books fetched %O", books);
  return books;
}

