// src/lib/commands/search.ts
async function searchCommand(options) {
  const { author, limit, json } = options;
  const spinner = ora("Fetching books...").start();
  try {
    const books = await getBooksByAuthor(author);
    spinner.succeed("Books loaded");
    const limited = limit ? books.slice(0, parseInt(limit, 10)) : books;
    const result = limited.map((b) => ({
      title: b.title,
      year: b.year
    }));
    formatOutput(result, json);
  } catch (err) {
    spinner.fail("Failed to fetch books");
    console.error(err);
  }
}

