// src/lib/services/llm.ts
var log2 = dist_default("book-cli:llm");
function buildPrompt(title, style) {
  switch (style) {
    case "pirate":
      return `Summarize the book "${title}" like a pirate speaking. Make it fun and dramatic.`;
    case "haiku":
      return `Summarize the book "${title}" as a haiku (3 lines, 5-7-5 syllables).`;
    case "shashi tharoor":
      return `Summarize the book "${title}" in the eloquent and sophisticated style of Shashi Tharoor.`;
    case "drseuss":
      return `Summarize the book "${title}" in a playful rhyming Dr. Seuss style.`;
    case "funny":
      return `Summarize the book "${title}" in a humorous and witty way.`;
    default:
      return `Summarize the book "${title}" in simple 3-4 lines.`;
  }
}
async function summarizeBook(title, style) {
  log2("Summarizing book %s with style %s", title, style);
  try {
    const prompt = buildPrompt(title, style);
    const result = await generateText({
      model: google("gemini-2.5-flash-lite"),
      prompt
    });
    return result.text;
  } catch (err) {
    log2("LLM error %O", err);
    return `"${title}" is a notable literary work.`;
  }
}

// src/lib/commands/summary.ts
async function summaryCommand(options) {
  const { title, style, json: json3 } = options;
  const summary = await summarizeBook(title, style);
  formatOutput({
    title,
    summary
  }, json3);
}

// src/lib/commands/random.ts
async function randomCommand(options) {
  const { author, style } = options;
  const books = await getBooksByAuthor(author);
  if (!books.length) {
    console.log("No books found");
    return;
  }
  const randomBook = books[Math.floor(Math.random() * books.length)];
  console.log(`\uD83D\uDCD6 ${randomBook.title}`);
  const summary = await summarizeBook(randomBook.title, style);
  console.log(summary);
}

