var program2 = new Command;
program2.name("book-cli").description("\uD83D\uDCDA CLI to search books and generate summaries").version("1.0.0");
program2.command("search").alias("s").description("Search books by author (titles only)").requiredOption("--author <name>", "Author name (e.g. Rowling)").option("--limit <number>", "Limit number of results", "5").option("--json", "Output in JSON format").action(searchCommand);
program2.command("summary").alias("sum").description("Get summary of a specific book").requiredOption("--title <title>", "Book title").option("--style <style>", "Summary style (funny, pirate, haiku, etc.)").option("--json", "Output in JSON format").action(summaryCommand);
program2.command("random").alias("r").description("Get a random book and its summary").requiredOption("--author <name>", "Author name").option("--style <style>", "Summary style").action(randomCommand);
program2.addHelpText("after", `
\uD83D\uDCCC All Commands & Options:

\uD83D\uDD0D search
  --author <name>       Author name
  --limit <number>      Limit results
  --json                JSON output

\uD83D\uDCD6 summary
  --title <title>       Book title
  --style <style>       funny | pirate | haiku
  --json                JSON output

\uD83C\uDFB2 random
  --author <name>       Author name
  --style <style>       Summary style

\uD83D\uDCCC Examples:
  $ book-cli search --author "Rowling"
  $ book-cli summary --title "Harry Potter"
`);
program2.parse();
